mapper.select:
SELECT s.id, s.name, s.no, s.gender, s.graduation_date, s.violation_count, s.violation_score, s.clazz_id, c.name AS clazz_name, s.create_time, s.update_time FROM student s LEFT JOIN clazz c ON s.clazz_id = c.id
AND s.name LIKE CONCAT('%', #{name}, '%')
AND s.degree = #{degree}
AND s.clazz_id = #{clazzId}
ORDER BY s.create_time DESC

mapper.delete:
delete from student where
id in
#{id}
